// Parse and validate payload from media.homeup.sg /api/generate-blueprint
const raw = $input.first().json;
const body = raw.body ?? raw;

const required = [
  "address",
  "property_type",
  "selling_points",
  "uploaded_by",
  "room_photos",
];

for (const field of required) {
  if (body[field] == null || body[field] === "") {
    throw new Error(`Missing required field: ${field}`);
  }
}

if (!Array.isArray(body.room_photos) || body.room_photos.length === 0) {
  throw new Error("room_photos must be a non-empty array");
}

for (const photo of body.room_photos) {
  if (!photo.label || !photo.r2_url) {
    throw new Error("Each room_photos entry needs label and r2_url");
  }
}

const roomList = `PROPERTY ADDRESS: ${body.address}\n\nROOMS:\n${body.room_photos
  .map(
    (photo) =>
      `- ${photo.label} (${photo.duration_seconds || body.seconds_per_room || 5}s): ${photo.r2_url}`,
  )
  .join("\n")}`;

const roomCount = body.room_photos.length;
const wordsPerRoom =
  Number(body.words_per_room) || Math.max(20, Math.floor(195 / roomCount));
const secondsPerRoom =
  Number(body.seconds_per_room) ||
  Math.max(5, Math.round((wordsPerRoom / 130) * 60));

return [
  {
    json: {
      address: body.address,
      property_type: body.property_type,
      rooms: body.rooms || "Not specified",
      listing_title: body.listing_title || "Not specified",
      listing_type: body.listing_type || "For Sale",
      bedrooms: body.bedrooms || "Not specified",
      bathrooms: body.bathrooms || "Not specified",
      sqft: body.sqft || "Not specified",
      area_sqm: body.area_sqm || "Not specified",
      price_range: body.price_range || "Not specified",
      price_psf: body.price_psf || "Not specified",
      tenure: body.tenure || "Not specified",
      condition: body.condition || "Not specified",
      selling_points: body.selling_points,
      renovation_status: body.renovation_status || "Move-in ready",
      agent_notes: body.agent_notes || "None",
      uploaded_by: body.uploaded_by,
      room_photos: body.room_photos,
      room_list: roomList,
      room_count: roomCount,
      words_per_room: wordsPerRoom,
      seconds_per_room: secondsPerRoom,
    },
  },
];

const raw = $input.first().json.content[0].text.trim();
const cleaned = raw
  .replace(/^```json/i, "")
  .replace(/^```/, "")
  .replace(/```$/, "")
  .trim();

let blueprint;
try {
  blueprint = JSON.parse(cleaned);
} catch (error) {
  throw new Error(
    "Failed to parse Claude blueprint JSON. Raw: " + cleaned.substring(0, 500),
  );
}

if (!blueprint.hook_script || !blueprint.room_scripts || !blueprint.cta_script) {
  throw new Error(
    "Blueprint missing required keys: " + Object.keys(blueprint).join(", "),
  );
}

const input = $("Parse & Validate Input").first().json;

const fullScript = [
  "=== HOOK ===",
  blueprint.hook_script,
  "",
  ...blueprint.room_scripts.flatMap((room) => [
    `=== ${room.label.toUpperCase()} (${room.duration_seconds}s) ===`,
    room.script,
    `[Presenter direction: ${room.presenter_direction}]`,
    "",
  ]),
  "=== CTA ===",
  blueprint.cta_script,
].join("\n");

const shotList = blueprint.room_scripts.map((room, index) => ({
  order: index + 1,
  label: room.label,
  duration_seconds: room.duration_seconds,
  script: room.script,
  presenter_direction: room.presenter_direction,
  higgsfield_prompt: room.higgsfield_prompt,
}));

const editInstructions = {
  edit_notes: blueprint.edit_notes,
  presentation_guide: blueprint.presentation_guide,
  colorgrade_notes: blueprint.colorgrade_notes || "",
  sequence: ["hook", ...blueprint.room_scripts.map((room) => room.label), "cta"],
};

return [
  {
    json: {
      address: input.address,
      property_type: input.property_type,
      uploaded_by: input.uploaded_by,
      room_photos: input.room_photos,
      full_script: fullScript,
      shot_list: shotList,
      edit_instructions: editInstructions,
      hook_script: blueprint.hook_script,
      cta_script: blueprint.cta_script,
      edit_notes: blueprint.edit_notes,
      presentation_guide: blueprint.presentation_guide,
      room_scripts: blueprint.room_scripts,
      colorgrade_notes: blueprint.colorgrade_notes || blueprint.edit_notes || "",
    },
  },
];

const supabaseResult = $input.first().json;
const blueprintId = supabaseResult.id;

if (!blueprintId) {
  throw new Error(
    "Supabase did not return a blueprint ID. Response: " +
      JSON.stringify(supabaseResult).substring(0, 300),
  );
}

const parsed = $("Parse Blueprint JSON").first().json;

return [
  {
    json: {
      ...parsed,
      blueprint_id: blueprintId,
    },
  },
];

