const { blueprint_id, room_photos } = $("Parse Approval Input").first().json;

return room_photos.map((photo) => ({
  json: {
    blueprint_id,
    label: photo.label,
    r2_url: photo.r2_url,
    higgsfield_prompt: photo.higgsfield_prompt,
    duration_seconds: photo.duration_seconds || 6,
    file_name:
      "room_clip_" + photo.label.toLowerCase().replace(/ /g, "_") + ".mp4",
    r2_key:
      "room-clips/" +
      blueprint_id +
      "/" +
      photo.label.toLowerCase().replace(/ /g, "_") +
      ".mp4",
  },
}));

const item = $input.first().json;
const baseUrl =
  "https://ixhikkbytusikgjiuvqa.supabase.co/functions/v1/generate-room-clip";

async function postClip(body, timeoutMs) {
  return await this.helpers.httpRequest({
    method: "POST",
    url: baseUrl,
    headers: { "Content-Type": "application/json" },
    body,
    json: true,
    timeout: timeoutMs,
  });
}

let startRes;
try {
  startRes = await postClip.call(
    this,
    {
      action: "start",
      blueprint_id: item.blueprint_id,
      label: item.label,
      r2_url: item.r2_url,
      higgsfield_prompt: item.higgsfield_prompt,
      duration_seconds: item.duration_seconds,
    },
    45000,
  );
} catch (error) {
  const message =
    error?.message ||
    error?.description ||
    (typeof error === "string" ? error : "Clip start request failed");
  return [{ json: { ...item, success: false, error: message, retryable: true } }];
}

const jobId = startRes?.job_id ?? startRes?.higgsfield_job_id;
if (!startRes?.success || !jobId) {
  return [
    {
      json: {
        ...item,
        success: false,
        error: startRes?.error || "Clip start did not return a job_id",
        retryable: startRes?.retryable ?? true,
        diagnostics: startRes?.diagnostics || null,
      },
    },
  ];
}

const maxAttempts = 40;

for (let attempt = 0; attempt < maxAttempts; attempt++) {
  if (attempt > 0) {
    await new Promise((resolve) => setTimeout(resolve, 15000));
  }

  let statusRes;
  try {
    statusRes = await postClip.call(
      this,
      { action: "status", job_id: jobId, label: item.label },
      20000,
    );
  } catch (error) {
    const message =
      error?.message ||
      error?.description ||
      (typeof error === "string" ? error : "Clip status request failed");
    if (attempt === maxAttempts - 1) {
      return [
        {
          json: {
            ...item,
            success: false,
            error: message,
            retryable: true,
            higgsfield_job_id: jobId,
          },
        },
      ];
    }
    continue;
  }

  if (statusRes?.status === "failed" || statusRes?.success === false) {
    return [
      {
        json: {
          ...item,
          success: false,
          error: statusRes?.error || "fal job failed",
          retryable: statusRes?.retryable ?? true,
          higgsfield_job_id: jobId,
          diagnostics: statusRes?.diagnostics || null,
        },
      },
    ];
  }

  if (statusRes?.status === "completed") {
    let resultRes;
    try {
      resultRes = await postClip.call(
        this,
        { action: "result", job_id: jobId, label: item.label },
        45000,
      );
    } catch (error) {
      const message =
        error?.message ||
        error?.description ||
        (typeof error === "string" ? error : "Clip result request failed");
      return [
        {
          json: {
            ...item,
            success: false,
            error: message,
            retryable: true,
            higgsfield_job_id: jobId,
          },
        },
      ];
    }

    if (resultRes?.video_url) {
      return [
        {
          json: {
            ...item,
            success: true,
            video_url: resultRes.video_url,
            higgsfield_job_id: jobId,
            diagnostics: {
              ...(startRes.diagnostics || {}),
              ...(statusRes.diagnostics || {}),
              ...(resultRes.diagnostics || {}),
              poll_attempts: attempt + 1,
            },
          },
        },
      ];
    }

    return [
      {
        json: {
          ...item,
          success: false,
          error: resultRes?.error || "fal result did not include video_url",
          retryable: true,
          higgsfield_job_id: jobId,
        },
      },
    ];
  }
}

return [
  {
    json: {
      ...item,
      success: false,
      error:
        "fal job is still processing after ~10 minutes. Please retry this room clip.",
      retryable: true,
      higgsfield_job_id: jobId,
    },
  },
];

const context = $("Split Rooms for Processing").item.json;
const response = $input.first().json;

const explicitError =
  response.error_message ||
  (typeof response.error === "string" ? response.error : null) ||
  response.error?.message ||
  response.message;

if (response.success === false || (explicitError && !response.video_url)) {
  return [
    {
      json: {
        ...context,
        clip_status: "error",
        error_message: explicitError || "Clip generation failed",
        retryable: response.retryable ?? true,
        metadata: {
          label: context.label,
          diagnostics: response.diagnostics || null,
          source: "generate-room-clip",
        },
      },
    },
  ];
}

const videoUrl =
  response.video_url || response.url || response.r2_url || response.clip_url;

if (!videoUrl) {
  return [
    {
      json: {
        ...context,
        clip_status: "error",
        error_message:
          "No video_url in clip response: " +
          JSON.stringify(response).substring(0, 300),
        retryable: true,
      },
    },
  ];
}

return [
  {
    json: {
      ...context,
      video_url: videoUrl,
      clip_status: "done",
      metadata: {
        label: context.label,
        diagnostics: response.diagnostics || null,
        source: "generate-room-clip",
      },
    },
  },
];

// Same value as MEDIA_WEBHOOK_SECRET in Vercel (media.homeup.sg).
// Edit this line in n8n after import — Code nodes cannot use credentials here.
const MEDIA_WEBHOOK_SECRET = "REPLACE_WITH_YOUR_SECRET";

const item = $input.first().json;

if (item.clip_status === "error" || !item.video_url || !item.r2_key) {
  return [{ json: item }];
}

const appUrl = "https://media.homeup.sg";

if (!MEDIA_WEBHOOK_SECRET || MEDIA_WEBHOOK_SECRET === "REPLACE_WITH_YOUR_SECRET") {
  return [
    {
      json: {
        ...item,
        metadata: {
          ...(item.metadata || {}),
          archive_skipped:
            "Set MEDIA_WEBHOOK_SECRET at the top of Archive Clip to R2 code",
        },
      },
    },
  ];
}

try {
  const archived = await this.helpers.httpRequest({
    method: "POST",
    url: `${appUrl}/api/clips/archive`,
    headers: {
      "Content-Type": "application/json",
      "x-media-webhook-secret": MEDIA_WEBHOOK_SECRET,
    },
    body: {
      source_url: item.video_url,
      r2_key: item.r2_key,
    },
    json: true,
    timeout: 120000,
  });

  return [
    {
      json: {
        ...item,
        video_url: archived.r2_url,
        file_size: archived.file_size,
        metadata: {
          ...(item.metadata || {}),
          archived_to_r2: true,
          original_source_url: item.video_url,
        },
      },
    },
  ];
} catch (error) {
  const message =
    error?.message ||
    error?.description ||
    (typeof error === "string" ? error : "Archive request failed");

  return [
    {
      json: {
        ...item,
        metadata: {
          ...(item.metadata || {}),
          archive_error: message,
        },
      },
    },
  ];
}
